function LPlatformUtil.IsLingDongDao()
	local strModel = USystemInfo.deviceModel
	local isNotchIphoneDevice = false
	if lingDongDaoIphoneDeviceList[strModel] then
		isNotchIphoneDevice = true
	end
	return isNotchIphoneDevice
end

function LPlatformUtil.IsIphoneNotch()
	local strModel = USystemInfo.deviceModel
	local isNotchIphoneDevice = false
	if notchIphoneDeviceList[strModel] then
		isNotchIphoneDevice = true
	end
	return isNotchIphoneDevice
end

function LPlatformUtil.GetIphoneNativeScaleFactor()
	local strModel = USystemInfo.deviceModel
	local val = notchIphoneDeviceList[strModel]
	return val
end

---设备类型：1：浏览器设备；2：PC设备；3：Andriod设备；4：iOS设备；5：webgl ; 6 鸿蒙
function LPlatformUtil.GetDeviceType()
	if CS.IsOSAndroid() then
		return 3
	elseif CS.IsOSIos() then
		return 4
	elseif CS.IsWebGL() then
		return 5
	elseif CS.IsOSOpenHarmony() then
		return 6
	end
	return 2
end

-- webgl 平台调用
function LPlatformUtil.IsInIos()
	local userAgent = LNativeHelper.GetUserAgent()
	-- LogWarn("IsInIos .. userAgent " ..tostring(userAgent))
	if not string.isempty(userAgent) then
		userAgent = string.lower(userAgent)
		if string.find(userAgent, "iphone") or string.find(userAgent, "ipad") or string.find(userAgent, "ipod") then
			return true
		end	
	end
	return false
end

-- webgl 平台调用
function LPlatformUtil.IsInAndroid()
	local userAgent = LNativeHelper.GetUserAgent()
	if not string.isempty(userAgent) then
		userAgent = string.lower(userAgent)
		if string.find(userAgent, "android") then
			return true
		end	
	end
	return false
end


function LPlatformUtil.GetDeviceName()
	if CS.IsOSAndroid() then
		return "Andriod设备"
	elseif CS.IsOSIos() then
		return "iOS设备"
	elseif CS.IsWebGL() then
		return "浏览器设备"
	elseif CS.IsOSOpenHarmony() then
		return "OpenHarmony设备"
	end
	return "PC设备" 
end

function LPlatformUtil.IsWifiValid()
	if LWxHelper.IsMiniGamePlatform() and LWxHelper.WxIsWifiEnable() then
		return true
	end

	if CS.IsWifiValid() then
		return true
	end

	return false
end

