function LPlatformUtil.GetNetworkName()
	if LPlatformUtil.IsWifiValid() then
		return 'WIFI'
	elseif CS.IsCarrierDataValid() then
		return '移动网络'
	end
	return '无'
end

function LPlatformUtil.GetDeviceWH()
	local rectW = 0
	local rectH = 0
	if CS.IsOSAndroid() then
		local realRect = LNativeHelper.GetDeviceDisplayRect()
		if not string.isempty(realRect) then
			local arrResult = string.split(realRect,"|") or {}
			rectW = tonumber(arrResult[1]) or 0
			rectH = tonumber(arrResult[2]) or 0
		end
	else
		local nowResolution = UnityEngine.Screen.currentResolution
		rectW = nowResolution.width
		rectH = nowResolution.height
    end

	return rectW, rectH
end

function LPlatformUtil.IsAssetFileExist(path)
	if(string.isempty(path)) then return false end
	if CS.IsOSAndroid() then
		return LNativeHelper.IsAssetFileExist(path)
	elseif CS.IsOSOpenHarmony() then
		return LNativeHelper.IsAssetFileExist(path)
	elseif CS.IsWebGL() then
		return false
	else
		return CS.FileExists(CS.StreamingPath()..path)
	end
	return true
end

--- 微信小程序 ios 送审 判断
function LPlatformUtil.IsWebGLIosApproval()
	if CS.IsWebGL() and LWxHelper.IsInIos() and PRODUCT_G_VER and PRODUCT_G_VER ~= 0 then
		return true
	end
	return false
end


return LPlatformUtil
